export class OpenAI {
  constructor(apiKey: string) {
    this.apiKey = apiKey;
  }
  async createChatCompletion(messages) {
    return this.request('/chat/completions', { method: 'POST', body: { messages } });
  }
}

export async function* streamChatCompletions(client, messages) {
  const response = await client.createChatCompletion(messages, { stream: true });
  for await (const chunk of response) {
    yield chunk;
  }
}
